using System;
using System.Diagnostics;
namespace HtmlToPdfConverter {
    public class PdfGenerator 
    {        
        private string WkHtmlToPdfPath = "path_to_wkhtmltopdf"; // replace with your wkhtmltopdf path, e.g., "/usr/local/bin" or similar on Linux systems and in PATH variable of Windows system respectively  
            
        public void Generate(string inputFilePath, string outputPdfPath, PdfOptions options) 
