           var startInfo = new ProcessStartInfo()    // Create a process Start Info object.      
                {                
                    FileName= WkHtmlToPdfPath ,     // Path to wkhtmltopdf executable file  
                     Arguments= $"-O{options.Orientation} -s{options.PageSize} \"{inputFilePath}\"  \"--outfile\" \"{outputPdfPath}\""    /* Add page size and orientation options here */,                    // Command line arguments to pass wkhtmltopdf  
                     UseShellExecute= false ,      // Do not use the shell execute method. This is required for using ProcessStartInfo in .NET Core or newer versions 
                };            
            try    {                
                  var process = Process.Start(startInfo);     /* Starts a new instance of wkhtmltopdf */                  
                    if (process == null) throw new Exception("Failed to start the PDF generation."); // Throw exception in case it fails  
                }  catch (Exception e){ Console.WriteLine("\nError: " +e .Message);}             /* Catch any exceptions and print them out*/                 
        }}         
    public enum PdfOptions { Small, Medium , Large };     // Define the options for page size in PDFs  
